import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const GENERATED_HEADER = `/* eslint-disable */
// AUTO-GENERATED FILE. DO NOT EDIT.
// Generated by web/scripts/generate-campaign-v2-types.mjs.

`;

const MODULE_NAME_BY_KEY = {
  relation: 'relation',
  location: 'location',
  locationState: 'locationState',
  session: 'session',
  event: 'event',
  effect: 'effect',
};

const ROOT_TYPE_NAME_BY_KEY = {
  relation: 'Relation',
  location: 'Location',
  locationState: 'LocationState',
  session: 'Session',
  event: 'Event',
  effect: 'Effect',
};

const repoRoot = path.resolve(fileURLToPath(new URL('../..', import.meta.url)));
const schemaRoot = path.join(repoRoot, 'schemas', 'campaign-v2');
const outputRoot = path.join(repoRoot, 'web', 'src', 'generated', 'campaign-v2');

function pascalCase(value) {
  return String(value)
    .replace(/\.schema\.json$/i, '')
    .replace(/[^a-zA-Z0-9]+/g, ' ')
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join('');
}

function quotePropertyName(name) {
  return /^[$A-Z_][0-9A-Z_$]*$/i.test(name) ? name : JSON.stringify(name);
}

function sortEntries(entries) {
  return [...entries].sort(([left], [right]) => left.localeCompare(right));
}

function normalizeAnyOf(types) {
  return [...new Set(types)].join(' | ');
}

function getLocalDefTypeName(moduleInfo, defName) {
  return `${moduleInfo.rootTypeName}${pascalCase(defName)}`;
}

function buildModuleInfoByFileName(entrypoints, schemaFiles) {
  const moduleInfoByFileName = new Map();

  for (const [key, fileName] of Object.entries(entrypoints)) {
    const schema = schemaFiles.get(fileName);
    const rootTypeName = ROOT_TYPE_NAME_BY_KEY[key] ?? pascalCase(key);
    const moduleInfo = {
      key,
      fileName,
      moduleName: MODULE_NAME_BY_KEY[key] ?? fileName.replace(/\.schema\.json$/i, ''),
      rootTypeName,
      schema,
      localDefNames: new Map(),
    };

    for (const defName of Object.keys(schema.$defs ?? {})) {
      moduleInfo.localDefNames.set(defName, getLocalDefTypeName(moduleInfo, defName));
    }

    moduleInfoByFileName.set(fileName, moduleInfo);
  }

  return moduleInfoByFileName;
}

function parseRef(ref) {
  const [fileName, fragment = ''] = ref.split('#');
  return {
    fileName,
    fragment,
  };
}

function getReferencedTypeName(ref, moduleInfo, moduleInfoByFileName, importMap) {
  const { fileName, fragment } = parseRef(ref);

  if (!fileName) {
    const defName = fragment.replace(/^\/\$defs\//, '');
    return moduleInfo.localDefNames.get(defName);
  }

  const targetModule = moduleInfoByFileName.get(fileName);
  if (!targetModule) {
    throw new Error(`Unknown schema reference target: ${ref}`);
  }

  let targetTypeName = targetModule.rootTypeName;
  if (fragment.startsWith('/$defs/')) {
    const defName = fragment.replace(/^\/\$defs\//, '');
    targetTypeName = targetModule.localDefNames.get(defName);
  }

  if (!targetTypeName) {
    throw new Error(`Unknown schema definition reference: ${ref}`);
  }

  if (targetModule.fileName === moduleInfo.fileName) {
    return targetTypeName;
  }

  const existingImports = importMap.get(targetModule.moduleName) ?? new Set();
  existingImports.add(targetTypeName);
  importMap.set(targetModule.moduleName, existingImports);
  return targetTypeName;
}

function schemaToType(schema, moduleInfo, moduleInfoByFileName, importMap) {
  if (!schema || typeof schema !== 'object') {
    return 'unknown';
  }

  if (schema.$ref) {
    return getReferencedTypeName(schema.$ref, moduleInfo, moduleInfoByFileName, importMap);
  }

  if (Object.prototype.hasOwnProperty.call(schema, 'const')) {
    return JSON.stringify(schema.const);
  }

  if (Array.isArray(schema.enum)) {
    return normalizeAnyOf(schema.enum.map((value) => JSON.stringify(value)));
  }

  if (Array.isArray(schema.anyOf)) {
    return normalizeAnyOf(schema.anyOf.map((entry) => schemaToType(entry, moduleInfo, moduleInfoByFileName, importMap)));
  }

  if (Array.isArray(schema.type)) {
    return normalizeAnyOf(
      schema.type.map((entry) => schemaToType({ ...schema, type: entry }, moduleInfo, moduleInfoByFileName, importMap)),
    );
  }

  switch (schema.type) {
    case 'object': {
      const propertyEntries = sortEntries(Object.entries(schema.properties ?? {}));
      if (propertyEntries.length === 0) {
        return 'Record<string, unknown>';
      }

      const required = new Set(schema.required ?? []);
      const lines = propertyEntries.map(([propertyName, propertySchema]) => {
        const optionalFlag = required.has(propertyName) ? '' : '?';
        const propertyType = schemaToType(propertySchema, moduleInfo, moduleInfoByFileName, importMap);
        return `  ${quotePropertyName(propertyName)}${optionalFlag}: ${propertyType};`;
      });

      return `{\n${lines.join('\n')}\n}`;
    }
    case 'array':
      return `Array<${schemaToType(schema.items ?? {}, moduleInfo, moduleInfoByFileName, importMap)}>`;
    case 'integer':
    case 'number':
      return 'number';
    case 'boolean':
      return 'boolean';
    case 'null':
      return 'null';
    case 'string':
      return 'string';
    default:
      return 'unknown';
  }
}

function renderModule(moduleInfo, moduleInfoByFileName) {
  const importMap = new Map();
  const lines = [GENERATED_HEADER];
  const defEntries = sortEntries(Object.entries(moduleInfo.schema.$defs ?? {}));

  for (const [defName, defSchema] of defEntries) {
    const typeName = moduleInfo.localDefNames.get(defName);
    const tsType = schemaToType(defSchema, moduleInfo, moduleInfoByFileName, importMap);
    lines.push(`export type ${typeName} = ${tsType};`, '');
  }

  const rootType = schemaToType(moduleInfo.schema, moduleInfo, moduleInfoByFileName, importMap);
  lines.push(`export type ${moduleInfo.rootTypeName} = ${rootType};`, '');

  const importLines = sortEntries(
    [...importMap.entries()].map(([moduleName, importedTypes]) => [
      moduleName,
      `import type { ${[...importedTypes].sort().join(', ')} } from './${moduleName}';`,
    ]),
  ).map(([, statement]) => statement);

  if (importLines.length > 0) {
    lines.splice(1, 0, ...importLines, '');
  }

  return `${lines.join('\n').trimEnd()}\n`;
}

async function main() {
  const manifestPath = path.join(schemaRoot, 'package.manifest.json');
  const manifest = JSON.parse(await fs.readFile(manifestPath, 'utf8'));
  const entrypoints = manifest.entrypoints ?? {};
  const schemaFiles = new Map();

  for (const fileName of Object.values(entrypoints)) {
    const schemaPath = path.join(schemaRoot, fileName);
    schemaFiles.set(fileName, JSON.parse(await fs.readFile(schemaPath, 'utf8')));
  }

  const moduleInfoByFileName = buildModuleInfoByFileName(entrypoints, schemaFiles);

  await fs.rm(outputRoot, { recursive: true, force: true });
  await fs.mkdir(outputRoot, { recursive: true });

  for (const [key, fileName] of Object.entries(entrypoints)) {
    const moduleInfo = moduleInfoByFileName.get(fileName);
    const moduleContents = renderModule(moduleInfo, moduleInfoByFileName);
    const outputPath = path.join(outputRoot, `${MODULE_NAME_BY_KEY[key] ?? moduleInfo.moduleName}.ts`);
    await fs.writeFile(outputPath, moduleContents, 'utf8');
  }

  const barrel = `${GENERATED_HEADER}${Object.values(MODULE_NAME_BY_KEY)
    .map((moduleName) => `export * from './${moduleName}';`)
    .join('\n')}\n`;
  await fs.writeFile(path.join(outputRoot, 'index.ts'), barrel, 'utf8');
}

await main();
